{
  "plaintext": "dữ liệu nhạy cảm cần mã hóa"
}

[
  { "id": 1, "title": "Dự án thí điểm GTSC", "status": "active" },
  { "id": 2, "title": "Nghiên cứu AI y tế",   "status": "pending" },
  { "id": 3, "title": "Hệ thống cảnh báo sớm", "status": "active" }
]

{
  "name": "soy-te",
  "description": "Sở Y Tế — báo cáo tình hình bệnh nhân",
  "sourceFields": [
    {
      "name": "ngay",
      "type": "date",
      "required": true
    },
    {
      "name": "ma_don_vi",
      "type": "string",
      "required": true
    },
    {
      "name": "so_benh_nhan",
      "type": "int",
      "required": true
    },
    {
      "name": "benh_tat",
      "type": "string",
      "required": false
    }
  ],
  "sinkFields": [
    {
      "sourceName": "ngay",
      "sinkName": "report_date"
    },
    {
      "sourceName": "ma_don_vi",
      "sinkName": "facility_code"
    },
    {
      "sourceName": "so_benh_nhan",
      "sinkName": "patient_count"
    },
    {
      "sourceName": "benh_tat",
      "sinkName": "disease_name",
      "transform": "upper"
    }
  ],
  "validations": [
    {
      "fieldName": "so_benh_nhan",
      "ruleType": "range",
      "ruleValue": "0-1000000"
    },
    {
      "fieldName": "ma_don_vi",
      "ruleType": "minLength",
      "ruleValue": "3"
    }
  ],
  "kafkaTopicPattern": "HEALTH_REPORT",
  "sinkHdfsPath": "/dmst/data/health/reports",
  "fileDownloadEnabled": false
}

{
  "name": "sogddt",
  "description": "Sở GD&ĐT — thống kê học sinh",
  "sourceFields": [
    {
      "name": "nam_hoc",
      "type": "string",
      "required": true
    },
    {
      "name": "truong",
      "type": "string",
      "required": true
    },
    {
      "name": "so_hoc_sinh",
      "type": "int",
      "required": true
    }
  ],
  "sinkFields": [
    {
      "sourceName": "nam_hoc",
      "sinkName": "school_year"
    },
    {
      "sourceName": "truong",
      "sinkName": "school_name",
      "transform": "trim"
    },
    {
      "sourceName": "so_hoc_sinh",
      "sinkName": "student_count"
    }
  ],
  "kafkaTopicPattern": "EDUCATION_DATA",
  "sinkHdfsPath": "/dmst/data/education",
  "fileDownloadEnabled": false
}

{
  "name": "so-tu-phap",
  "description": "Sở Tư Pháp — hồ sơ có file đính kèm",
  "sourceFields": [
    {
      "name": "maDonVi",
      "type": "string",
      "required": true
    },
    {
      "name": "danhSachTepDuLieu",
      "type": "string",
      "required": false
    }
  ],
  "sinkFields": [
    {
      "sourceName": "maDonVi",
      "sinkName": "don_vi_code"
    }
  ],
  "kafkaTopicPattern": "TU_PHAP_DATA",
  "sinkHdfsPath": "/dmst/data/tu-phap",
  "fileDownloadEnabled": true,
  "fileFieldConfig": {
    "fileListPath": "$.danhSachTepDuLieu",
    "itemIdField": "itemId",
    "fileIdField": "fileId",
    "tenTepField": "tenTep",
    "phienBanField": "phienBan",
    "checkSumField": "checkSum",
    "duongDanField": "duongDan"
  }
}

{
  "name": "so-noi-vu",
  "description": "Sở Nội Vụ — file trong nested object",
  "sourceFields": [
    {
      "name": "phanPhoi",
      "type": "string",
      "required": false
    }
  ],
  "sinkFields": [
    {
      "sourceName": "phanPhoi",
      "sinkName": "phan_phoi"
    }
  ],
  "kafkaTopicPattern": "NOI_VU_DATA",
  "sinkHdfsPath": "/dmst/data/noi-vu",
  "fileDownloadEnabled": true,
  "fileFieldConfig": {
    "fileListPath": "$.phanPhoi.mucPhanPhoi",
    "itemIdField": "itemId",
    "fileIdField": "id",
    "tenTepField": "tenTep",
    "phienBanField": "version",
    "checkSumField": "md5",
    "duongDanField": "path"
  }
}
